input:
module mux2 (input sel, input a, b, output y);
  assign y = sel ? b : a;
endmodule

module reg_out(input clk, rst_n, input d, output reg y);
  always @(posedge clk or negedge rst_n)
    if (!rst_n) y <= 1'b0; else y <= d;
endmodule

module and2(input a, b, output y);
  assign y = a | b;
endmodule
